import java.nio.charset.Charset;
import java.nio.charset.CharsetEncoder;
import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        CharsetEncoder encoder = Charset.defaultCharset().newEncoder();
        byte[] inputBytes = encoder.encode(userInput).array();

        // Limit the buffer size to avoid buffer overflow
        int bufferSize = Math.min(inputBytes.length, 10);
        byte[] buffer = new byte[bufferSize];

        // Copy inputBytes content into buffer
        System.arraycopy(inputBytes, 0, buffer, 0, bufferSize);

        System.out.println("Buffer contents: " + new String(buffer, Charset.defaultCharset()));
    }
}

### Explanation:
취약유형: Buffer Overflow
